package test.rice.concisegen;

import main.rice.concisegen.ConciseSetGenerator;
import main.rice.obj.APyObj;
import main.rice.obj.PyIntObj;
import main.rice.test.TestCase;
import main.rice.test.TestResults;
import org.junit.jupiter.api.Test;

import java.util.*;

import static org.junit.jupiter.api.Assertions.*;

class ConciseSetGeneratorFullTest {

    private TestCase createTestCase(int... args) {
        List<APyObj> objArgs = new ArrayList<>();
        for (int arg : args) {
            objArgs.add(new PyIntObj(arg));
        }
        return new TestCase(objArgs);
    }

    @Test
    void testSetCoverSimple() {
        // Setup: 2 test cases, 2 files, each test catches one file
        List<TestCase> allCases = Arrays.asList(
            createTestCase(1),
            createTestCase(2)
        );
        List<Set<Integer>> caseToFiles = Arrays.asList(
            new HashSet<>(Arrays.asList(0)),
            new HashSet<>(Arrays.asList(1))
        );
        Set<Integer> wrongSet = new HashSet<>(Arrays.asList(0, 1));

        TestResults results = new TestResults(allCases, caseToFiles, wrongSet);
        Set<TestCase> result = ConciseSetGenerator.setCover(results);

        assertEquals(2, result.size());
        assertTrue(result.contains(allCases.get(0)));
        assertTrue(result.contains(allCases.get(1)));
    }

    @Test
    void testSetCoverGreedy() {
        // Setup:
        // TC0 catches {0, 1}
        // TC1 catches {1, 2}
        // TC2 catches {2, 0}
        // All together catch {0, 1, 2}
        // Greedy should pick TC0, then TC1 (or TC2).
        List<TestCase> allCases = Arrays.asList(
            createTestCase(0),
            createTestCase(1),
            createTestCase(2)
        );
        List<Set<Integer>> caseToFiles = Arrays.asList(
            new HashSet<>(Arrays.asList(0, 1)),
            new HashSet<>(Arrays.asList(1, 2)),
            new HashSet<>(Arrays.asList(2, 0))
        );
        Set<Integer> wrongSet = new HashSet<>(Arrays.asList(0, 1, 2));

        TestResults results = new TestResults(allCases, caseToFiles, wrongSet);
        Set<TestCase> result = ConciseSetGenerator.setCover(results);

        assertEquals(2, result.size());
        // Greedy starts with TC0 (catches 0, 1). Remaining: {2}.
        // Then it looks for case that catches {2}. TC1 or TC2.
        // It should pick TC1 because it comes first in a tie.
        assertTrue(result.contains(allCases.get(0)));
        assertTrue(result.contains(allCases.get(1)) || result.contains(allCases.get(2)));
    }

    @Test
    void testSetCoverEmpty() {
        TestResults results = new TestResults(new ArrayList<>(), new ArrayList<>(), new HashSet<>());
        Set<TestCase> result = ConciseSetGenerator.setCover(results);
        assertEquals(0, result.size());
    }
}

package test.rice.node;

import main.rice.node.PyBoolNode;
import main.rice.node.PyFloatNode;
import main.rice.node.PyIntNode;
import main.rice.obj.APyObj;
import main.rice.obj.PyBoolObj;
import main.rice.obj.PyFloatObj;
import main.rice.obj.PyIntObj;
import org.junit.jupiter.api.Test;

import java.util.Arrays;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

class PyNodeGenTest {

    @Test
    void testPyIntNodeGenExVals() {
        PyIntNode node = new PyIntNode();
        List<Integer> domain = Arrays.asList(1, 2, 3);
        node.setExDomain(domain);
        List<PyIntObj> vals = node.genExVals();
        assertEquals(3, vals.size());
        assertEquals(1, vals.get(0).getValue());
        assertEquals(2, vals.get(1).getValue());
        assertEquals(3, vals.get(2).getValue());
    }

    @Test
    void testPyIntNodeGenRandVal() {
        PyIntNode node = new PyIntNode();
        List<Integer> domain = Arrays.asList(1, 2, 3);
        node.setRanDomain(domain);
        APyObj val = node.genRandVal();
        assertTrue(val instanceof PyIntObj);
        assertTrue(domain.contains((Integer) val.getValue()));
    }

    @Test
    void testPyBoolNodeGenExVals() {
        PyBoolNode node = new PyBoolNode();
        List<Integer> domain = Arrays.asList(0, 1, 2);
        node.setExDomain(domain);
        List<PyBoolObj> vals = node.genExVals();
        assertEquals(3, vals.size());
        assertFalse(vals.get(0).getValue());
        assertTrue(vals.get(1).getValue());
        assertTrue(vals.get(2).getValue());
    }

    @Test
    void testPyFloatNodeGenExVals() {
        PyFloatNode node = new PyFloatNode();
        List<Double> domain = Arrays.asList(1.1, 2.2);
        node.setExDomain(domain);
        List<PyFloatObj> vals = node.genExVals();
        assertEquals(2, vals.size());
        assertEquals(1.1, vals.get(0).getValue());
        assertEquals(2.2, vals.get(1).getValue());
    }

    @Test
    void testPrimitiveNodesChildren() {
        PyIntNode intNode = new PyIntNode();
        assertNull(intNode.getLeftChild());
        assertNull(intNode.getRightChild());

        PyBoolNode boolNode = new PyBoolNode();
        assertNull(boolNode.getLeftChild());
        assertNull(boolNode.getRightChild());

        PyFloatNode floatNode = new PyFloatNode();
        assertNull(floatNode.getLeftChild());
        assertNull(floatNode.getRightChild());
    }
}

package main.rice.concisegen;

import main.rice.test.TestCase;
import main.rice.test.TestResults;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

/**
 * A class for generating a concise set of test cases.
 */
public class ConciseSetGenerator {

    /**
     * Finds a minimal set of test cases that covers all buggy implementations.
     * Uses a greedy set cover algorithm.
     *
     * @param results the test results
     * @return a set of test cases that covers all buggy implementations
     */
    public static Set<TestCase> setCover(TestResults results) {
        // We'll be working with a copy of the wrong set to avoid mutation
        Set<Integer> uncoveredFiles = new HashSet<>(results.getWrongSet());
        List<TestCase> allCases = new ArrayList<>();
        List<Set<Integer>> caseToFiles = new ArrayList<>();

        // Also copy the case-to-files mapping
        for (Set<Integer> filesCaught : results.getCaseToFiles()) {
            caseToFiles.add(new HashSet<>(filesCaught));
        }

        Set<TestCase> selectedTestCases = new HashSet<>();

        // While there are still uncovered failing implementations
        while (!uncoveredFiles.isEmpty()) {
            int maxUncoveredCaught = -1;
            int bestCaseIndex = -1;

            // Iterate through all test cases to find the one that catches the most
            // currently uncovered files
            for (int i = 0; i < caseToFiles.size(); i++) {
                Set<Integer> filesCaughtByThisCase = caseToFiles.get(i);

                // Count how many of the files caught by this case are currently uncovered
                int count = 0;
                for (Integer fileIdx : filesCaughtByThisCase) {
                    if (uncoveredFiles.contains(fileIdx)) {
                        count++;
                    }
                }

                // If this case is better than the current best, update it.
                // We use > to pick the first one in case of a tie, for determinism.
                if (count > maxUncoveredCaught) {
                    maxUncoveredCaught = count;
                    bestCaseIndex = i;
                }
            }

            // If we didn't find any test case that catches more uncovered files, break
            // (this shouldn't happen if wrongSet is consistent with caseToFiles)
            if (bestCaseIndex == -1 || maxUncoveredCaught == 0) {
                break;
            }

            // Add the best test case to our selected set
            TestCase bestCase = results.getTestCase(bestCaseIndex);
            selectedTestCases.add(bestCase);

            // Mark all files caught by this test case as covered
            uncoveredFiles.removeAll(caseToFiles.get(bestCaseIndex));
        }

        return selectedTestCases;
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyFloatObj;

import java.util.ArrayList;
import java.util.List;
import java.util.Random;

/**
 * A leaf node representing the generation of Python float objects.
 */
public class PyFloatNode extends APyNode<Double> {

    /**
     * Returns null because this is a leaf node.
     *
     * @return null
     */
    @Override
    public APyNode<?> getLeftChild() {
        return null;
    }

    /**
     * Returns null because this is a leaf node.
     *
     * @return null
     */
    @Override
    public APyNode<?> getRightChild() {
        return null;
    }

    /**
     * Generates all PyFloatObj values from the exhaustive domain.
     *
     * @return a list of all PyFloatObj values in the exhaustive domain
     */
    @Override
    public List<PyFloatObj> genExVals() {
        List<PyFloatObj> vals = new ArrayList<>();
        if (this.exDomain != null) {
            for (Double val : this.exDomain) {
                vals.add(new PyFloatObj(val));
            }
        }
        return vals;
    }

    /**
     * Generates a random PyFloatObj value from the random domain.
     *
     * @return a random PyFloatObj value from the random domain
     */
    @Override
    public APyObj genRandVal() {
        if (this.ranDomain == null || this.ranDomain.isEmpty()) {
            return null;
        }
        Random rand = new Random();
        Double val = this.ranDomain.get(rand.nextInt(this.ranDomain.size()));
        return new PyFloatObj(val);
    }
}

