package main.rice.node;

import main.rice.obj.APyObj;
import java.util.List;

/**
 * An abstract class representing a node in the Python object generation tree.
 * Each node is responsible for generating Python objects from a domain.
 *
 * @param <T> the type of the elements in the domain
 */
public abstract class APyNode<T> {

    /**
     * The exhaustive domain for this node.
     */
    protected List<T> exDomain;

    /**
     * The random domain for this node.
     */
    protected List<T> ranDomain;

    /**
     * Returns the exhaustive domain that was set.
     *
     * @return the exhaustive domain
     */
    public List<T> getExDomain() {
        return this.exDomain;
    }

    /**
     * Sets the exhaustive domain.
     *
     * @param exDomain the exhaustive domain to set
     */
    public void setExDomain(List<T> exDomain) {
        this.exDomain = exDomain;
    }

    /**
     * Returns the random domain that was set.
     *
     * @return the random domain
     */
    public List<T> getRanDomain() {
        return this.ranDomain;
    }

    /**
     * Sets the random domain.
     *
     * @param ranDomain the random domain to set
     */
    public void setRanDomain(List<T> ranDomain) {
        this.ranDomain = ranDomain;
    }

    /**
     * Returns the left child of this node. For primitive nodes, this is null.
     *
     * @return the left child
     */
    public abstract APyNode<?> getLeftChild();

    /**
     * Returns the right child of this node. For primitive nodes, this is null.
     *
     * @return the right child
     */
    public abstract APyNode<?> getRightChild();

    /**
     * Generates all values in the exhaustive domain.
     *
     * @return a list of all values in the exhaustive domain
     */
    public abstract List<? extends APyObj> genExVals();

    /**
     * Generates a random value from the random domain.
     *
     * @return a random value from the random domain
     */
    public abstract APyObj genRandVal();
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyBoolObj;

import java.util.ArrayList;
import java.util.List;
import java.util.Random;

/**
 * A leaf node representing the generation of Python bool objects.
 */
public class PyBoolNode extends APyNode<Integer> {

    /**
     * Returns null because this is a leaf node.
     *
     * @return null
     */
    @Override
    public APyNode<?> getLeftChild() {
        return null;
    }

    /**
     * Returns null because this is a leaf node.
     *
     * @return null
     */
    @Override
    public APyNode<?> getRightChild() {
        return null;
    }

    /**
     * Generates all PyBoolObj values from the exhaustive domain.
     *
     * @return a list of all PyBoolObj values in the exhaustive domain
     */
    @Override
    public List<PyBoolObj> genExVals() {
        List<PyBoolObj> vals = new ArrayList<>();
        if (this.exDomain != null) {
            for (Integer val : this.exDomain) {
                // In Python, 0 is False, and other numbers are True
                vals.add(new PyBoolObj(val != 0));
            }
        }
        return vals;
    }

    /**
     * Generates a random PyBoolObj value from the random domain.
     *
     * @return a random PyBoolObj value from the random domain
     */
    @Override
    public APyObj genRandVal() {
        if (this.ranDomain == null || this.ranDomain.isEmpty()) {
            return null;
        }
        Random rand = new Random();
        Integer val = this.ranDomain.get(rand.nextInt(this.ranDomain.size()));
        return new PyBoolObj(val != 0);
    }
}

