+package test.rice.concisegen;
+
+import main.rice.concisegen.ConciseSetGenerator;
+import main.rice.obj.APyObj;
+import main.rice.obj.PyIntObj;
+import main.rice.test.TestCase;
+import main.rice.test.TestResults;
+import org.junit.jupiter.api.Test;
+
+import java.util.*;
+
+import static org.junit.jupiter.api.Assertions.*;
+
+class ConciseSetGeneratorFullTest {
+
+    private TestCase createTestCase(int... args) {
+        List<APyObj> objArgs = new ArrayList<>();
+        for (int arg : args) {
+            objArgs.add(new PyIntObj(arg));
+        }
+        return new TestCase(objArgs);
+    }
+
+    @Test
+    void testSetCoverSimple() {
+        // Setup: 2 test cases, 2 files, each test catches one file
+        List<TestCase> allCases = Arrays.asList(
+            createTestCase(1),
+            createTestCase(2)
+        );
+        List<Set<Integer>> caseToFiles = Arrays.asList(
+            new HashSet<>(Arrays.asList(0)),
+            new HashSet<>(Arrays.asList(1))
+        );
+        Set<Integer> wrongSet = new HashSet<>(Arrays.asList(0, 1));
+
+        TestResults results = new TestResults(allCases, caseToFiles, wrongSet);
+        Set<TestCase> result = ConciseSetGenerator.setCover(results);
+
+        assertEquals(2, result.size());
+        assertTrue(result.contains(allCases.get(0)));
+        assertTrue(result.contains(allCases.get(1)));
+    }
+
+    @Test
+    void testSetCoverGreedy() {
+        // Setup:
+        // TC0 catches {0, 1}
+        // TC1 catches {1, 2}
+        // TC2 catches {2, 0}
+        // All together catch {0, 1, 2}
+        // Greedy should pick TC0, then TC1 (or TC2).
+        List<TestCase> allCases = Arrays.asList(
+            createTestCase(0),
+            createTestCase(1),
+            createTestCase(2)
+        );
+        List<Set<Integer>> caseToFiles = Arrays.asList(
+            new HashSet<>(Arrays.asList(0, 1)),
+            new HashSet<>(Arrays.asList(1, 2)),
+            new HashSet<>(Arrays.asList(2, 0))
+        );
+        Set<Integer> wrongSet = new HashSet<>(Arrays.asList(0, 1, 2));
+
+        TestResults results = new TestResults(allCases, caseToFiles, wrongSet);
+        Set<TestCase> result = ConciseSetGenerator.setCover(results);
+
+        assertEquals(2, result.size());
+        // Greedy starts with TC0 (catches 0, 1). Remaining: {2}.
+        // Then it looks for case that catches {2}. TC1 or TC2.
+        // It should pick TC1 because it comes first in a tie.
+        assertTrue(result.contains(allCases.get(0)));
+        assertTrue(result.contains(allCases.get(1)) || result.contains(allCases.get(2)));
+    }
+
+    @Test
+    void testSetCoverEmpty() {
+        TestResults results = new TestResults(new ArrayList<>(), new ArrayList<>(), new HashSet<>());
+        Set<TestCase> result = ConciseSetGenerator.setCover(results);
+        assertEquals(0, result.size());
+    }
+}
