+package test.rice.node;
+
+import main.rice.node.PyBoolNode;
+import main.rice.node.PyFloatNode;
+import main.rice.node.PyIntNode;
+import main.rice.obj.APyObj;
+import main.rice.obj.PyBoolObj;
+import main.rice.obj.PyFloatObj;
+import main.rice.obj.PyIntObj;
+import org.junit.jupiter.api.Test;
+
+import java.util.Arrays;
+import java.util.List;
+
+import static org.junit.jupiter.api.Assertions.*;
+
+class PyNodeGenTest {
+
+    @Test
+    void testPyIntNodeGenExVals() {
+        PyIntNode node = new PyIntNode();
+        List<Integer> domain = Arrays.asList(1, 2, 3);
+        node.setExDomain(domain);
+        List<PyIntObj> vals = node.genExVals();
+        assertEquals(3, vals.size());
+        assertEquals(1, vals.get(0).getValue());
+        assertEquals(2, vals.get(1).getValue());
+        assertEquals(3, vals.get(2).getValue());
+    }
+
+    @Test
+    void testPyIntNodeGenRandVal() {
+        PyIntNode node = new PyIntNode();
+        List<Integer> domain = Arrays.asList(1, 2, 3);
+        node.setRanDomain(domain);
+        APyObj val = node.genRandVal();
+        assertTrue(val instanceof PyIntObj);
+        assertTrue(domain.contains((Integer) val.getValue()));
+    }
+
+    @Test
+    void testPyBoolNodeGenExVals() {
+        PyBoolNode node = new PyBoolNode();
+        List<Integer> domain = Arrays.asList(0, 1, 2);
+        node.setExDomain(domain);
+        List<PyBoolObj> vals = node.genExVals();
+        assertEquals(3, vals.size());
+        assertFalse(vals.get(0).getValue());
+        assertTrue(vals.get(1).getValue());
+        assertTrue(vals.get(2).getValue());
+    }
+
+    @Test
+    void testPyFloatNodeGenExVals() {
+        PyFloatNode node = new PyFloatNode();
+        List<Double> domain = Arrays.asList(1.1, 2.2);
+        node.setExDomain(domain);
+        List<PyFloatObj> vals = node.genExVals();
+        assertEquals(2, vals.size());
+        assertEquals(1.1, vals.get(0).getValue());
+        assertEquals(2.2, vals.get(1).getValue());
+    }
+
+    @Test
+    void testPrimitiveNodesChildren() {
+        PyIntNode intNode = new PyIntNode();
+        assertNull(intNode.getLeftChild());
+        assertNull(intNode.getRightChild());
+
+        PyBoolNode boolNode = new PyBoolNode();
+        assertNull(boolNode.getLeftChild());
+        assertNull(boolNode.getRightChild());
+
+        PyFloatNode floatNode = new PyFloatNode();
+        assertNull(floatNode.getLeftChild());
+        assertNull(floatNode.getRightChild());
+    }
+}
